search:Advanced Error Handling in NestJS.content:
- Use `nest new project-name` to create a new NestJS project.
- Update dependencies using `npm update`.
- Configure logging levels in `app.module.ts`:
  ```typescript
  import { Module } from '@nestjs/common';
  import { APP_FILTER, APP_INTERCEPTOR } from '@nestjs/core';
  import { AllExceptionsFilter } from './filters/all-exceptions.filter';
  import { LoggingInterceptor } from './interceptors/logging.interceptor';

  @Module({
    providers: [
      {
        provide: APP_FILTER,
        useClass: AllExceptionsFilter,
      },
      {
        provide: APP_INTERCEPTOR,
        useClass: LoggingInterceptor,
      },
    ],
  })
  export class AppModule {}
  ```
- Use `Logger` service for logging:
  ```typescript
  import { Injectable, Logger } from '@nestjs/common';

  @Injectable()
  export class AppService {
    private readonly logger = new Logger(AppService.name);

    getHello(): string {
      this.logger.log('Getting hello message');
      return 'Hello World!';
    }
  }
  ```
- Configure Winston for advanced logging:
  ```typescript
  import { Module } from '@nestjs/common';
  import { APP_FILTER, APP_INTERCEPTOR } from '@nestjs/core';
  import { AllExceptionsFilter } from './filters/all-exceptions.filter';
  import { LoggingInterceptor } from './interceptors/logging.interceptor';
  import { WinstonModule } from 'nest-winston';
  import * as winston from 'winston';

  @Module({
    imports: [
      WinstonModule.forRoot({
        transports: [
          new winston.transports.Console(),
          new winston.transports.File({ filename: 'combined.log' }),
        ],
      }),
    ],
    providers: [
      {
        provide: APP_FILTER,
        useClass: AllExceptionsFilter,
      },
      {
        provide: APP_INTERCEPTOR,
        useClass: LoggingInterceptor,
      },
    ],
  })
  export class AppModule {}
  ```
- Use `nest generate interceptor logging` to scaffold a logging interceptor.
- Use `nest generate filter all-exceptions` to scaffold an exception filter.
